#include <bits/stdc++.h>
using namespace std;
const int N=1e6+6;
int n,m,nxt[N];
char a[N],b[N];
int main(){
	scanf("%s%s",a,b);
	n=strlen(a),m=strlen(b);
    nxt[0]=0;
	for(int i=1,j=0;i<m;i++){
        while(j && b[i]!=b[j])
            j=nxt[j-1];
        if(b[i]==b[j])
            j++;
        nxt[i]=j;
    }
	for(int i=0,j=0;i<n;i++){
		while(j && a[i]!=b[j])
            j=nxt[j-1];
        if(a[i]==b[j])
            j++;
		if(j==m){
			printf("%d\n",i-m+2);
			j=nxt[j-1];
		}
	}
	for(int i=0;i<m;i++)
		printf("%d ",nxt[i]);
	return 0;
}
